import{_ as e,o as a,c as p,ag as r}from"./chunks/framework.D--JA8_b.js";const u=JSON.parse('{"title":"时隔二十年，重启博客","description":"","frontmatter":{},"headers":[],"relativePath":"posts/restart-blog.md","filePath":"posts/restart-blog.md","lastUpdated":null}'),o={name:"posts/restart-blog.md"};function s(l,t,i,n,_,d){return a(),p("div",null,[...t[0]||(t[0]=[r('<h1 id="时隔二十年-重启博客" tabindex="-1">时隔二十年，重启博客 <a class="header-anchor" href="#时隔二十年-重启博客" aria-label="Permalink to &quot;时隔二十年，重启博客&quot;">​</a></h1><p>发布时间：2026-03-11 · 标签：#生活 #随笔 #博客</p><hr><p>算一算，距离上次认真写博客，居然快过去二十年了。</p><p>人生有多少个二十年呢？当年还是个对互联网充满好奇的学生，为了搭一个博客，蹲在电脑前折腾好几天：买服务器、备案域名、配置 LAMP 环境、调试 WordPress 主题、解决各种奇奇怪怪的兼容问题... 光是让网站能正常打开，就已经花掉了半个月的零花钱。</p><p>那时候觉得，能在互联网上有一块属于自己的小地方，写点没人看的文字，是件特别酷的事情。</p><p>后来工作越来越忙，生活的琐事越来越多，这块小地方也就慢慢荒废了。域名忘了续费，服务器到期没再买，曾经写过的文字也消失在互联网的尘埃里，连个备份都没留下。</p><p>前段时间想重新写点东西，惊讶地发现现在搭建个博客居然这么简单：</p><ul><li>不需要买服务器，GitHub Pages 免费托管</li><li>不需要买域名，github.io 自带二级域名</li><li>不需要折腾环境，几条命令就能构建部署</li><li>甚至连代码都不用写，用现成的框架几分钟就能生成一个好看的博客</li></ul><p>刚才更新 About 页面的时候，我只改了几行 Markdown，双击一下部署脚本，几十秒后刷新网页就看到了更新。这种便捷性，放在二十年前是想都不敢想的。</p><p>科技改变生活，真的不是一句空话。</p><p>二十年前折腾博客的那个少年，可能不会想到二十年后，自己会用 AI 助手搭建新的博客，用更成熟的心态重新开始记录。</p><p>希望这次能坚持下去。 毕竟，文字是有力量的，记录是有意义的。</p><hr><p><em>本文由 OpenClaw 智能助手协助排版发布</em></p>',15)])])}const m=e(o,[["render",s]]);export{u as __pageData,m as default};
